import { resolvePath } from "@typespec/compiler";
import { createTester, expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

/**
 * A tester WITHOUT auto `.using("State")` so multi-file fixtures can control
 * their own `using` declarations — needed for dataset-file-path tests that
 * rely on structured file paths (not the exempt /test/main.tsp).
 */
const DatasetTester = createTester(resolvePath(import.meta.dirname, "../.."), {
  libraries: ["@a10n/blueprint-typespec", "@a10n/typespec-dbml"],
}).importLibraries();

describe("@eval", () => {
  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval:Products.A10nBlueprintEngine.Features.SystemAuthoring.proof_has_parent:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.SystemAuthoring.proof_has_parent:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_eval
    it("nested inside @component at Evals.<Feature>.E<NNN> — Must priority", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Review Quality" })
          namespace Evals.MyFeature.E001 {}
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_05
    it("nested inside @component — Should priority", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Secondary Quality" })
          namespace Evals.MyFeature.E001 {}
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_06
    it("nested inside @component — Could priority", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Nice to have" })
          namespace Evals.MyFeature.E001 {}
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_07
    it("nested inside @component — Wont priority", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Out of scope" })
          namespace Evals.MyFeature.E001 {}
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_08
    it("multiple evals for different features in one component", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval 1" })
          namespace Evals.FeatureA.E001 {}

          @eval(#{ title: "Eval 2" })
          namespace Evals.FeatureA.E002 {}
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_09
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_signal:Products.A10nBlueprintEngine.Features.SystemAuthoring.signal_id_shape:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_feature_config:Products.A10nBlueprintEngine.Features.SystemAuthoring.signal_id_shape:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_signal:Products.A10nBlueprintEngine.Features.SystemAuthoring.signal_has_method:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_feature_config:Products.A10nBlueprintEngine.Features.SystemAuthoring.signal_has_method:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_signal
    it("with @signal inside eval", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Review Quality" })
          namespace Evals.MyFeature.E001 {
            @signal(#{
              title: "Comment is actionable",
              method: SignalMethod.Probabilistic,
              criteria: "Does the comment include a suggested fix?",
              examples: #[]
            })
            op E001_01(): boolean;
          }
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_16
    it("unresolved inline ref in @signal criteria", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace Evals.MyFeature.E001 {
            model RealType {}
            @signal(#{
              title: "Test",
              method: SignalMethod.Deterministic,
              criteria: "Uses {@RealType} and {@GhostType}",
              examples: #[]
            })
            op E001_01(): boolean;
          }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/unresolved-inline-ref",
        message: /GhostType/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_10
    it("at top level — no @component ancestor", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @eval(#{ title: "Orphan Eval" })
        namespace Evals.MyFeature.E001 {}
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /component/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_11
    it("inside a @feature — not a @component", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @eval(#{ title: "Misplaced Eval" })
          namespace Evals.MyFeature.E001 {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /component/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_12
    it("wrong naming — missing Evals prefix", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace MyFeature.E001 {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-eval-namespace",
        message: /Evals\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_13
    it("wrong naming — missing feature segment", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace Evals.E001 {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-eval-namespace",
        message: /Evals\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_14
    it("wrong naming — lowercase feature initial", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace Evals.myFeature.E001 {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-eval-namespace",
        message: /Evals\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_15
    it("wrong naming — only two digits in E", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace Evals.MyFeature.E01 {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-eval-namespace",
        message: /Evals\./,
      });
    });
  });
});

describe("@signal", () => {
  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_02
    it("directly inside @eval namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace Evals.MyFeature.E001 {
            @signal(#{
              title: "My signal",
              method: SignalMethod.Probabilistic,
              criteria: "Does it work?",
              examples: #[]
            })
            op E001_01(): boolean;
          }
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_17
    it("op name not matching E{NNN}_{NN}", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @eval(#{ title: "Eval" })
          namespace Evals.MyFeature.E001 {
            @signal(#{
              title: "My signal",
              method: SignalMethod.Probabilistic,
              criteria: "Does it work?",
              examples: #[]
            })
            op actionable_signal(): boolean;
          }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/signal-id-shape",
        message: /actionable_signal/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_18
    it("outside @eval — directly in @component", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @signal(#{
            title: "Orphan signal",
            method: SignalMethod.Probabilistic,
            criteria: "Does it work?",
            examples: #[]
          })
          op orphan(): boolean;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-decorator-context",
        message: /signal/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_19
    it("at top level", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @signal(#{
          title: "Orphan signal",
          method: SignalMethod.Probabilistic,
          criteria: "Does it work?",
          examples: #[]
        })
        op orphan(): boolean;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-decorator-context",
        message: /signal/,
      });
    });
  });
});

