describe("@evalSuite — suite_no_reads / suite_no_writes", () => {
  // Shared store fixture used by these tests
  const STORE_FIXTURE_RW = `
    @component(#{ type: ComponentType.Store })
    namespace Components.DataFileStore {
      @storage(#{ provider: StorageProvider.filesystem, root: ".data" })
      namespace Storage {
        @mediaTypeHint("application/yaml")
        @storageObject(#{ path: "items.yaml" })
        model ItemRegistry {}
      }
    }
  `;

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_25
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.SystemAuthoring.eval_file_numbering:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.SystemAuthoring.eval_file_numbering:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.SystemAuthoring.case_has_priority:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.SystemAuthoring.case_has_priority:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_no_reads:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_signal:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_no_reads:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_no_reads:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_no_writes:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_signal:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_no_writes:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_no_writes:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_returns_void:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_returns_void:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_has_inputs:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_has_inputs:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.inputs_model_local:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.inputs_model_local:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.under_component:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_scoring:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.under_component:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.under_component:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_config_impact:Products.A10nBlueprintEngine.Features.DatasetAuthoring.under_component:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_namespace:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_scoring:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_namespace:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_namespace:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_with_signals:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_signal:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_with_signals:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_with_signals:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_eval_suite:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_has_priority:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_signal:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_has_priority:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_dataset:Products.A10nBlueprintEngine.Features.EvalSuiteAuthoring.suite_has_priority:must
        it("@evalSuite with neither @reads nor @writes — zero diagnostics", async () => {
      const runner = await Tester.createInstance();

      // Feature + invariant so @projects is valid
      await runner.compile(`
        @feature
        namespace Products.P.Features.F {
          @invariant(#{ predicate: "p", why: "w" })
          op inv(): void;
        }

        ${STORE_FIXTURE_RW}

        @component(#{ type: ComponentType.Agent })
        @dependsOn([Components.DataFileStore])
        namespace Components.ReviewAgent {
          @eval(#{ title: "Quality Eval" })
          namespace Evals.Quality.E001 {
            @signal(#{
              title: "Quality signal",
              method: SignalMethod.Probabilistic,
              criteria: "Is it good?",
              examples: #[]
            })
            @projects(Products.P.Features.F.inv)
            op E001_01(): boolean;

            @scoring(#{
              formula: "E001_01",
              examples: #[],
              boundaryCases: #[]
            })
            @calls([E001_01])
            op Score(): float32;
          }

          @dataset(#{ title: "Items" })
          @reads([Components.DataFileStore.Storage.ItemRegistry])
          @projects(Products.P.Features.F.inv)
          op items(): void;

          model SuiteInputs {}

          @evalSuite(#{
            title: "Quality Suite",
            priority: Priority.Must,
            expects: #["{@Components.ReviewAgent.Evals.Quality.E001.Score} >= 0.8"]
          })
          @calls([Components.ReviewAgent.Evals.Quality.E001.Score, Components.ReviewAgent.items])
          op QualitySuite(inputs: SuiteInputs): void;
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T007.T007_26
    it("@evalSuite carrying @reads — emits suite-no-reads", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        namespace Components {
          @component(#{ type: ComponentType.Store })
          namespace DataStore {
            model DataRow { id: string; }
          }

          @component(#{ type: ComponentType.Agent })
          @dependsOn([Components.DataStore])
          namespace ReviewAgent {
            model SuiteInputs {}

            @evalSuite(#{
              title: "Quality Suite",
              priority: Priority.Must,
              expects: #[]
            })
            @reads([Components.DataStore.DataRow])
            op QualitySuite(inputs: SuiteInputs): void;
          }
        }
      `);
      const readsWritesDiags = diagnostics.filter((d) => d.code === "@a10n/blueprint-typespec/suite-no-reads");
      expectDiagnostics(readsWritesDiags, {
        code: "@a10n/blueprint-typespec/suite-no-reads",
        message: /QualitySuite/,
      });
    });

    it("@evalSuite carrying @writes — emits evalSuite-no-reads-writes (writes)", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        namespace Components {
          @component(#{ type: ComponentType.Store })
          namespace DataStore {
            model DataRow { id: string; }
          }

          @component(#{ type: ComponentType.Agent })
          @dependsOn([Components.DataStore])
          namespace ReviewAgent {
            model SuiteInputs {}

            @evalSuite(#{
              title: "Quality Suite",
              priority: Priority.Must,
              expects: #[]
            })
            @writes([Components.DataStore.DataRow])
            op QualitySuite(inputs: SuiteInputs): void;
          }
        }
      `);
      const readsWritesDiags = diagnostics.filter((d) => d.code === "@a10n/blueprint-typespec/evalSuite-no-reads-writes");
      expectDiagnostics(readsWritesDiags, {
        code: "@a10n/blueprint-typespec/evalSuite-no-reads-writes",
        message: /QualitySuite/,
      });
    });
  });
});

